	for(int i=x;i<=2*maxn;i+=i&-i)

    	tree[i]+=v;

}

ll ask(int x){

    ll ans=0;

    for(int i=x;i>0;i-=i&-i)

    	ans+=tree[i];

    return ans;

}

bool check(int mid){

	memset(tree,0,sizeof(tree));

	pre[0]=0;

	ll ans=0;

	for(int i=1;i<=n;++i)

		pre[i]=pre[i-1]+(a[i]>=mid?1:-1);

	for(int i=0;i<=n;++i){

		ans+=ask(pre[i]+maxn); 

		add(pre[i]+maxn,1);

	}

	return ans>=n*(n+1)/4;

}

