int lowbit(int x){return x&(-x);}

void update(int x,int n){

	for (int i=x;i<=n;i+=lowbit(i)) {

		sum[i]++;

	}

}

int getSum(int x) {

	int ans = 0;

	for (int i=x;i>0;i-=lowbit(i)) {

		ans += sum[i];

	}

	return ans;

}

long long check(int x) {

	b[0] = 0;c[0] = 0;

	for (int i=1;i<=n;i++) {

		if (a[i]<=x) b[i] = 1;

		else b[i] = -1;

	}

	for (int i=1;i<=n;i++) {

		b[i] = b[i-1] + b[i];

		c[i] = b[i];

	}

	sort(c,c+1+n);

	int cnt = 1;

	map<int,int> mp;

	mp[c[0]] = 1;

	for (int i=1;i<=n;i++) {

		if (c[i]!=c[i-1]) {

			cnt++;

			mp[c[i]] = cnt;

		}

	}

	for (int i=0;i<=cnt;i++) sum[i]=0;

	long long res = 0;

	update(mp[0],cnt);

	for (int i=1;i<=n;i++) {

		res += getSum(mp[b[i]]-1);

		update(mp[b[i]],cnt);

	}

	return res;

}

