int L, R;



void no()

{

	cout<<"NO"<<endl;

	exit(0);

}



void dfs(int x)

{

	U[x] = true;



	if (x & 1)

	{

		if (IN[x] > OUT[x]) no();

		R += IN[x] - OUT[x];

	}

	else

	{

		if (OUT[x] > IN[x]) no();

		L += OUT[x] - IN[x];

	}



	FOR (i, 0, SZ(g[x]))

