        return;
    int mid = (l + r) / 2;
    merge(a, l, mid);
    merge(a, mid + 1, r);
    int i = l, j = mid + 1, index = l;
    while (i <= mid && j <= r) {
        if (a[i] > a[j]) {
            c[index++] = a[j++];
        } else {
            c[index++] = a[i++];
        }
    }
    while (i <= mid)
        c[index++] = a[i++];
    while (j <= r)
        c[index++] = a[j++];
    for (int k = l; k <= r; ++k)
        a[k] = c[k];
}

