    if(i == 0) return 0 ;
    if(mem[i] != -1) return mem[i] ;
    mem[i] = 2e9 ;
    for(int j = 1 ; j <= k && i - j >= 0 ; j++)
        mem[i] = min( jump(i - j) + abs(h[i] - h[i - j]) , mem[i] ) ;
    return mem[i] ;
}

